class Solution {
    public int countBinarySubstrings(String s) {
        int count = 0;
        int n = s.length();
        for (int i = 0; i < n; i++) {
            int prevCount = 0;
            for (int j = i; j < n; j++) {
                if (s.charAt(j) == s.charAt(i)) {
                    prevCount++;
                } else {
                    count += prevCount;
                    prevCount = 0;
                }
            }
        }
        return count;
    }
}
```

